import{_ as a,o,c as t,ae as i}from"./chunks/framework.BEtfQoF7.js";const p=JSON.parse('{"title":"Week 13 · 2026년 3월 23–27일","description":"Claude Code v2.1.83부터 v2.1.85까지 공개된 6가지 기능과 기타 개선 사항 정리","frontmatter":{"title":"Week 13 · 2026년 3월 23–27일","description":"Claude Code v2.1.83부터 v2.1.85까지 공개된 6가지 기능과 기타 개선 사항 정리"},"headers":[],"relativePath":"whats-new/2026-w13.md","filePath":"whats-new/2026-w13.md","lastUpdated":null}'),r={name:"whats-new/2026-w13.md"};function s(l,e,d,n,c,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="week-13-·-2026년-3월-23–27일" tabindex="-1">Week 13 · 2026년 3월 23–27일 <a class="header-anchor" href="#week-13-·-2026년-3월-23–27일" aria-label="Permalink to &quot;Week 13 · 2026년 3월 23–27일&quot;">​</a></h1><p>릴리스: v2.1.83 → v2.1.85, 기능 6종</p><h2 id="feature-1-auto-mode-research-preview" tabindex="-1">Feature 1: Auto mode (research preview) <a class="header-anchor" href="#feature-1-auto-mode-research-preview" aria-label="Permalink to &quot;Feature 1: Auto mode (research preview)&quot;">​</a></h2><p>Auto mode는 권한 요청을 분류기에 넘기는 기능. 안전한 수정과 명령은 사용자를 방해하지 않고 실행되며, 파괴적이거나 수상한 작업은 차단되고 별도로 표시됨. 모든 파일 쓰기마다 일일이 승인하는 방식과 <code>--dangerously-skip-permissions</code>로 실행하는 방식 사이의 중간 지점.</p><p>Shift+Tab으로 auto로 전환하거나, <code>.claude/settings.json</code>의 permissions에서 <code>defaultMode: &quot;auto&quot;</code>로 설정 가능.</p><h2 id="feature-2-computer-use-desktop" tabindex="-1">Feature 2: Computer use (Desktop) <a class="header-anchor" href="#feature-2-computer-use-desktop" aria-label="Permalink to &quot;Feature 2: Computer use (Desktop)&quot;">​</a></h2><p>이제 Claude는 Claude Code Desktop 앱에서 실제 데스크톱을 제어 가능. 네이티브 앱 열기, iOS 시뮬레이터 클릭 조작, 하드웨어 제어 패널 다루기, 화면에서 변경 사항 확인까지 지원. 기본값은 비활성화이며, 각 작업 전에 확인 요청 제공.</p><h2 id="feature-3-pr-auto-fix-web" tabindex="-1">Feature 3: PR auto-fix (Web) <a class="header-anchor" href="#feature-3-pr-auto-fix-web" aria-label="Permalink to &quot;Feature 3: PR auto-fix (Web)&quot;">​</a></h2><p>PR을 열 때 스위치만 켜 두면 됨. Claude가 CI를 지켜보다가 실패를 수정하고, 사소한 지적까지 처리한 뒤, 초록불이 켜질 때까지 푸시 진행.</p><h2 id="feature-4-transcript-search-v2-1-83" tabindex="-1">Feature 4: Transcript search (v2.1.83) <a class="header-anchor" href="#feature-4-transcript-search-v2-1-83" aria-label="Permalink to &quot;Feature 4: Transcript search (v2.1.83)&quot;">​</a></h2><p>transcript 모드에서 <code>/</code>를 눌러 대화 검색 가능. <code>n</code>과 <code>N</code>으로 검색 결과 사이 이동 가능.</p><h2 id="feature-5-powershell-tool-preview-v2-1-84" tabindex="-1">Feature 5: PowerShell tool (preview, v2.1.84) <a class="header-anchor" href="#feature-5-powershell-tool-preview-v2-1-84" aria-label="Permalink to &quot;Feature 5: PowerShell tool (preview, v2.1.84)&quot;">​</a></h2><p>Windows에서 Bash와 함께 네이티브 PowerShell tool 지원 추가. <code>CLAUDE_CODE_USE_POWERSHELL_TOOL=1</code> 설정으로 활성화.</p><h2 id="feature-6-conditional-hooks-v2-1-85" tabindex="-1">Feature 6: Conditional hooks (v2.1.85) <a class="header-anchor" href="#feature-6-conditional-hooks-v2-1-85" aria-label="Permalink to &quot;Feature 6: Conditional hooks (v2.1.85)&quot;">​</a></h2><p>이제 hooks에서 권한 규칙 문법을 사용하는 <code>&quot;if&quot;</code> 필드 선언 가능.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;if&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(git commit *)&quot;</span></span></code></pre></div><h2 id="기타-개선-사항" tabindex="-1">기타 개선 사항 <a class="header-anchor" href="#기타-개선-사항" aria-label="Permalink to &quot;기타 개선 사항&quot;">​</a></h2><ul><li>Plugin userConfig 공개 전환</li><li>붙여넣은 이미지에 <code>[Image #N]</code> 칩 삽입</li><li><code>managed-settings.d/</code> drop-in 디렉터리 지원</li><li><code>CwdChanged</code>, <code>FileChanged</code> hook 이벤트 추가</li><li>Agents frontmatter에서 <code>initialPrompt</code> 선언 가능</li><li><code>Ctrl+X Ctrl+E</code>로 외부 편집기 열기</li><li>Claude 응답 중에도 <code>/status</code> 동작</li><li>Deep link를 선호 터미널에서 열기</li><li>75분 이상 유휴 상태 후 <code>/clear</code> 유도 표시</li><li>VS Code에 rate limit 배너, Esc 두 번으로 rewind picker 지원</li></ul>',18)])])}const k=a(r,[["render",s]]);export{p as __pageData,k as default};
